let sahurCronStarted = false

function startAutoSahur(alya) {
    if (sahurCronStarted) return
    sahurCronStarted = true

    nodecron.schedule('0 0 3 * * *', async () => {
        try {
            let groups = Object.keys(autosahurData)

            if (groups.length === 0) return

            for (let groupId of groups) {
                    await alya.sendMessage(groupId, {
    audio: { 
        url: 'https://c.termai.cc/a103/Rk9YWBB.mp3' 
    },
    mimetype: 'audio/mpeg',
    ptt: true,
    contextInfo: {
        externalAdReply: {
            showAdAttribution: false,
            mediaType: 1,
            title: `рҹ“ў UDAH WAKTUNYA SAHUR рҹ“ў`,
            body: `Gas Yok Mari makan sebelum Masuk waktu imsak! рҹҚҪпёҸ`,
            renderLargerThumbnail: true,
            thumbnailUrl: 'https://c.termai.cc/i190/gK6.jpg',
            sourceUrl: "https://yuugames.free.nf"
        }
    }
}).catch(_ => _);
                    await new Promise(resolve => setTimeout(resolve, 2000));
			}
        } catch (err) {
            console.log('Auto Sahur Error:', err)
        }
    }, {
        scheduled: true,
        timezone: "Asia/Jakarta"
    })
}

