async function dramaboxEpisodeM3U8(url) {
    const r = await axios.get(url, {
        headers: {
            'User-Agent': 'Mozilla/5.0',
            'Referer': 'https://www.dramabox.com/'
        }
    })

    const json = JSON.parse(
        r.data.match(/<script id="__NEXT_DATA__"[^>]*>([\s\S]*?)<\/script>/)[1]
    )

    const ep =
        json.props?.pageProps?.episode ||
        json.props?.pageProps?.video ||
        {}

    const m3u8 =
        ep.playUrl ||
        ep.hlsUrl ||
        ep.videoUrl

    if (!m3u8) throw new Error('M3U8 tidak ditemukan')

    return m3u8
}

async function groupStatus(jid, content) {
  const { backgroundColor } = content;
  delete content.backgroundColor;
  const inside = await baileys.generateWAMessageContent(content, {
    upload: alya.waUploadToServer,
    backgroundColor
  });
  const messageSecret = crypto.randomBytes(32);
  const m = baileys.generateWAMessageFromContent(jid, {
    messageContextInfo: {
      messageSecret
    },
    groupStatusMessageV2: {
      message: {
        ...inside,
        messageContextInfo: {
          messageSecret
        }
      }
    }
  }, {});
  await alya.relayMessage(jid, m.message, {
    messageId: m.key.id
  });
  return m;
}

