// Auto download tiktok
if (
  budy.startsWith('https://vt.tiktok.com/') || 
  budy.startsWith('https://www.tiktok.com/') || 
  budy.startsWith('https://t.tiktok.com/') || 
  budy.startsWith('https://vm.tiktok.com/')
) {

  let biaya = 3
  if (db.users[m.sender].limit < biaya) {
    return replyalya(`вқҢ Limit kamu tidak cukup!\n\nрҹ’Ў Limit dibutuhkan: ${biaya}`)
  }

  await alya.sendMessage(m.chat, { react: { text: 'вҸі', key: m.key } })

  try {
    const axios = require('axios')
    const cheerio = require('cheerio')

    const headers = {
      'Content-Type': 'application/x-www-form-urlencoded',
      Accept: 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
      Origin: 'https://savett.cc',
      Referer: 'https://savett.cc/en1/download',
      'User-Agent': 'Mozilla/5.0 (Linux; Android 10)'
    }

    const page = await axios.get('https://savett.cc/en1/download')
    const csrf = page.data.match(/name="csrf_token" value="([^"]+)"/)?.[1]

    const cookie = page.headers['set-cookie']
      .map(v => v.split(';')[0])
      .join('; ')

    const post = await axios.post(
      'https://savett.cc/en1/download',
      `csrf_token=${encodeURIComponent(csrf)}&url=${encodeURIComponent(budy)}`,
      { headers: { ...headers, Cookie: cookie } }
    )

    const $ = cheerio.load(post.data)

    const stats = []
    $('#video-info .my-1 span').each((_, el) => stats.push($(el).text().trim()))

    const data = {
      username: $('#video-info h3').first().text().trim() || '-',
      views: stats[0] || '0',
      likes: stats[1] || '0',
      bookmarks: stats[2] || '0',
      comments: stats[3] || '0',
      shares: stats[4] || '0',
      duration: $('#video-info p.text-muted').first().text().replace(/Duration:/i, '').trim(),
      type: null,
      mp4: { nowm: [], wm: [] },
      mp3: [],
      slides: []
    }

    const slides = $('.carousel-item[data-data]')

    if (slides.length) {
      data.type = 'photo'

      slides.each((_, el) => {
        try {
          const json = JSON.parse($(el).attr('data-data').replace(/&quot;/g, '"'))
          json.URL?.forEach(u => data.slides.push(u))
        } catch {}
      })

    } else {

      data.type = 'video'

      $('#formatselect option').each((_, el) => {
        const label = $(el).text().toLowerCase()
        const raw = $(el).attr('value')
        if (!raw) return

        try {
          const json = JSON.parse(raw.replace(/&quot;/g, '"'))

          if (label.includes('mp4') && !label.includes('watermark'))
            data.mp4.nowm.push(...json.URL)

          if (label.includes('watermark'))
            data.mp4.wm.push(...json.URL)

          if (label.includes('mp3'))
            data.mp3.push(...json.URL)

        } catch {}
      })
    }

    // PHOTO POST
    if (data.type === 'photo' && data.slides.length) {

      let cards = await Promise.all(
        data.slides.map(async (img, i) => ({
          header: proto.Message.InteractiveMessage.Header.create({
            ...(await prepareWAMessageMedia(
              { image: { url: img } },
              { upload: alya.waUploadToServer }
            )),
            title: '',
            subtitle: `Foto ${i + 1} dari ${data.slides.length}`,
            hasMediaAttachment: false
          }),
          body: { text: '' },
          nativeFlowMessage: { buttons: [] }
        }))
      )

      let msg = generateWAMessageFromContent(
        m.chat,
        {
          viewOnceMessage: {
            message: {
              interactiveMessage: {
                body: {
                  text: `рҹ“ё *Tiktok Photo*
рҹ‘Ө User : *${data.username}*
вқӨпёҸ Like : ${data.likes}
рҹ’¬ Komen: ${data.comments}
рҹ”„ Share: ${data.shares}
рҹ‘Җ View : ${data.views}`
                },
                carouselMessage: { cards, messageVersion: 1 }
              }
            }
          }
        },
        { quoted: m }
      )

      db.users[m.sender].limit -= biaya

      await alya.sendMessage(m.chat, { react: { text: 'вң…', key: m.key } })
      return alya.relayMessage(m.chat, msg.message, { messageId: msg.key.id })
    }

    const videoUrl = data.mp4.nowm[0] || data.mp4.wm[0]
    if (!videoUrl) throw 'Video tidak ditemukan'

    await alya.sendMessage(
      m.chat,
      {
        video: { url: videoUrl },
        caption: `рҹҺҘ *Tiktok Video*
рҹ‘Ө User : *${data.username}*
вҸұ Durasi: ${data.duration}
вқӨпёҸ Like  : ${data.likes}
рҹ’¬ Komen : ${data.comments}
рҹ”„ Share : ${data.shares}
рҹ‘Җ View  : ${data.views}`,
        buttons: [
          {
            buttonId: `${prefix}ttaudio ${budy}`,
            buttonText: { displayText: 'рҹҺө Ambil Musik' },
            type: 1
          }
        ],
        headerType: 4
      },
      { quoted: m }
    )

    db.users[m.sender].limit -= biaya

    await alya.sendMessage(m.chat, { react: { text: 'вң…', key: m.key } })

  } catch (err) {
    console.error(err)
    await alya.sendMessage(m.chat, { react: { text: 'вқҢ', key: m.key } })
    replyalya('вқҢ Gagal mengambil data TikTok.')
  }
}
