  const layananList = Array.isArray(res.data?.data) ? res.data.data : []
  if (!layananList.length) return m.reply(`рҹҡ© Tidak ada layanan ditemukan.\nрҹ’¬ ${res.data?.message || 'Tidak diketahui'}`)

