function autoClearSession() {
    const sessionDir = './Alyachan';
    const clearInterval = 24 * 60 * 60 * 1000;
    
    setInterval(async () => {
        try {
            const files = fs.readdirSync(sessionDir);
            const filteredFiles = files.filter(file => 
                file.startsWith('pre-key') ||
                file.startsWith('sender-key') ||
                file.startsWith('session-') ||
                file.startsWith('app-state')
            );

            if (filteredFiles.length === 0) {
                console.log(chalk.blue.bold('рҹ“Ӯ [AUTO CLEAN] No session files to clean. Everything is tidy! рҹ“‘'));
                return;
            }

            console.log(chalk.yellow.bold('рҹ“Ӯ [AUTO CLEAN] Starting session cleanup... рҹ—ғпёҸ'));
            
            filteredFiles.forEach(file => {
                fs.unlinkSync(path.join(sessionDir, file));
            });

            console.log(chalk.green.bold(`рҹ—ғпёҸ [AUTO CLEAN] Successfully removed ${filteredFiles.length} session files! рҹ“Ӯ`));
        } catch (error) {
            console.error(chalk.red.bold('рҹ“‘ [AUTO CLEAN ERROR]'), chalk.red.bold(error));
        }
    }, clearInterval);
}
